const html = "<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>Catalina Cosmetic</title>\n  <script src=\"https://cdn.tailwindcss.com?plugins=forms\"></script>\n  <script src=\"https://unpkg.com/@supabase/supabase-js@2\"></script>\n  <link href=\"https://fonts.googleapis.com/css2?family=Manrope:wght@300;400;500;600;700;800&family=Material+Symbols+Outlined:wght@300;400;500&display=swap\" rel=\"stylesheet\" />\n  <script>\n    tailwind.config = {\n      theme: {\n        extend: {\n          colors: {\n            ink: \"#1f2a2e\",\n            muted: \"#617078\",\n            line: \"#d9e2e7\",\n            porcelain: \"#f7fafb\",\n            mist: \"#e9f0f3\",\n            sage: \"#496b62\",\n            clay: \"#a96f5d\",\n            cream: \"#fffdf8\"\n          },\n          borderRadius: { DEFAULT: \"0.125rem\", lg: \"0.25rem\", xl: \"0.5rem\" },\n          fontFamily: { sans: [\"Manrope\", \"sans-serif\"] }\n        }\n      }\n    };\n  </script>\n  <style>\n    body { font-family: Manrope, sans-serif; }\n    .material-symbols-outlined { font-variation-settings: \"FILL\" 0, \"wght\" 350, \"GRAD\" 0, \"opsz\" 24; }\n    .page { display: none; }\n    .page.active { display: block; }\n    .nav-link, button, select { cursor: pointer; }\n    .scroll-thin::-webkit-scrollbar { height: 8px; width: 8px; }\n    .scroll-thin::-webkit-scrollbar-thumb { background: #b9c7cd; border-radius: 999px; }\n  </style>\n</head>\n<body class=\"bg-porcelain text-ink\">\n  <nav class=\"fixed top-0 z-50 w-full border-b border-line/70 bg-cream/90 backdrop-blur\">\n    <div class=\"mx-auto flex h-20 max-w-7xl items-center justify-between px-5 md:px-8\">\n      <button class=\"nav-link text-left text-2xl font-extrabold tracking-tight uppercase\" data-page=\"home\">Catalina</button>\n      <div class=\"hidden items-center gap-7 text-sm font-semibold text-muted md:flex\">\n        <button class=\"nav-link hover:text-ink\" data-page=\"catalog\">Productos</button>\n        <button class=\"nav-link hover:text-ink\" data-page=\"profile\">Mi perfil</button>\n        <button class=\"nav-link hover:text-ink\" data-page=\"tracking\">Rastrear pedido</button>\n        <button class=\"nav-link hover:text-ink\" data-page=\"admin\">Admin</button>\n      </div>\n      <div class=\"flex items-center gap-3\">\n        <button class=\"nav-link rounded-lg border border-line bg-white px-3 py-2 text-sm font-bold hover:border-sage\" data-page=\"cart\">\n          <span class=\"material-symbols-outlined align-middle text-lg\">shopping_bag</span>\n          <span id=\"cart-pill\">0</span>\n        </button>\n        <button class=\"nav-link rounded-lg bg-sage px-4 py-2 text-sm font-bold text-white md:hidden\" data-page=\"admin\">Admin</button>\n      </div>\n    </div>\n  </nav>\n\n  <main class=\"pt-20\">\n    <section id=\"page-home\" class=\"page active\">\n      <div class=\"mx-auto grid min-h-[calc(100vh-5rem)] max-w-7xl grid-cols-1 items-center gap-10 px-5 py-12 md:px-8 lg:grid-cols-12\">\n        <div class=\"lg:col-span-6\">\n          <p class=\"mb-4 text-xs font-extrabold uppercase tracking-[0.22em] text-clay\">Skin care & hair care</p>\n          <h1 class=\"max-w-3xl text-5xl font-extrabold leading-[0.95] tracking-tight md:text-7xl\">Rutinas limpias, pedidos claros.</h1>\n          <p class=\"mt-7 max-w-xl text-lg leading-8 text-muted\">Ecommerce para formulas de cuidado facial y capilar con carrito, perfiles de cliente, seguimiento de pedidos y administracion operativa.</p>\n          <div class=\"mt-9 flex flex-wrap gap-3\">\n            <button class=\"nav-link rounded-lg bg-sage px-6 py-4 font-bold text-white hover:bg-ink\" data-page=\"catalog\">Ver productos</button>\n            <button class=\"nav-link rounded-lg border border-line bg-white px-6 py-4 font-bold hover:border-sage\" data-page=\"tracking\">Consultar pedido</button>\n          </div>\n        </div>\n        <div class=\"lg:col-span-6\">\n          <div class=\"relative overflow-hidden rounded-xl bg-mist\">\n            <img class=\"h-[560px] w-full object-cover\" src=\"https://images.unsplash.com/photo-1620916566398-39f1143ab7be?auto=format&fit=crop&w=1200&q=80\" alt=\"Productos de cuidado personal Catalina\" />\n            <div class=\"absolute bottom-5 left-5 right-5 grid grid-cols-3 gap-3 rounded-lg bg-white/90 p-4 shadow-xl backdrop-blur\">\n              <div><p class=\"text-xs font-bold uppercase text-muted\">Pedidos</p><p class=\"text-2xl font-extrabold\" id=\"metric-orders\">0</p></div>\n              <div><p class=\"text-xs font-bold uppercase text-muted\">Clientes</p><p class=\"text-2xl font-extrabold\" id=\"metric-customers\">0</p></div>\n              <div><p class=\"text-xs font-bold uppercase text-muted\">Ingresos</p><p class=\"text-2xl font-extrabold\" id=\"metric-revenue\">$0</p></div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </section>\n\n    <section id=\"page-catalog\" class=\"page\">\n      <div class=\"mx-auto max-w-7xl px-5 py-12 md:px-8\">\n        <div class=\"flex flex-col justify-between gap-5 md:flex-row md:items-end\">\n          <div>\n            <p class=\"text-xs font-extrabold uppercase tracking-[0.2em] text-clay\">Catalogo</p>\n            <h2 class=\"mt-2 text-4xl font-extrabold tracking-tight\">Productos Catalina</h2>\n          </div>\n          <div class=\"flex flex-col gap-3 sm:flex-row\">\n            <input id=\"catalog-search\" class=\"rounded-lg border-line bg-white px-4 py-3 text-sm\" placeholder=\"Buscar producto\" />\n            <select id=\"catalog-filter\" class=\"rounded-lg border-line bg-white px-4 py-3 text-sm\">\n              <option value=\"all\">Todas las categorias</option>\n              <option value=\"Piel\">Piel</option>\n              <option value=\"Cabello\">Cabello</option>\n              <option value=\"Kit\">Kit</option>\n            </select>\n          </div>\n        </div>\n        <div id=\"product-grid\" class=\"mt-9 grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-3\"></div>\n      </div>\n    </section>\n\n    <section id=\"page-cart\" class=\"page\">\n      <div class=\"mx-auto grid max-w-7xl grid-cols-1 gap-8 px-5 py-12 md:px-8 lg:grid-cols-12\">\n        <div class=\"lg:col-span-8\">\n          <h2 class=\"text-4xl font-extrabold tracking-tight\">Carrito</h2>\n          <div id=\"cart-items\" class=\"mt-8 space-y-4\"></div>\n          <div id=\"cart-empty\" class=\"mt-8 rounded-xl border border-dashed border-line bg-white p-12 text-center text-muted\">Tu carrito esta vacio.</div>\n        </div>\n        <aside class=\"h-fit rounded-xl bg-white p-6 shadow-sm lg:col-span-4\">\n          <h3 class=\"text-xs font-extrabold uppercase tracking-[0.2em] text-muted\">Resumen</h3>\n          <div class=\"mt-6 space-y-4 text-sm\">\n            <div class=\"flex justify-between\"><span class=\"text-muted\">Subtotal</span><strong id=\"summary-subtotal\">$0.00</strong></div>\n            <div class=\"flex justify-between\"><span class=\"text-muted\">Envio</span><strong id=\"summary-shipping\">$0.00</strong></div>\n            <div class=\"flex justify-between border-t border-line pt-4 text-lg\"><span>Total</span><strong id=\"summary-total\">$0.00</strong></div>\n          </div>\n          <label class=\"mt-6 block text-xs font-bold uppercase tracking-widest text-muted\">Cliente</label>\n          <select id=\"checkout-customer\" class=\"mt-2 w-full rounded-lg border-line bg-porcelain px-3 py-3 text-sm\"></select>\n          <button id=\"checkout-btn\" class=\"mt-5 w-full rounded-lg bg-sage px-5 py-4 font-extrabold uppercase tracking-widest text-white hover:bg-ink\">Crear pedido</button>\n        </aside>\n      </div>\n    </section>\n\n    <section id=\"page-profile\" class=\"page\">\n      <div class=\"mx-auto max-w-7xl px-5 py-12 md:px-8\">\n        <div class=\"grid grid-cols-1 gap-8 lg:grid-cols-12\">\n          <aside class=\"rounded-xl bg-white p-6 shadow-sm lg:col-span-4\">\n            <p class=\"text-xs font-extrabold uppercase tracking-[0.2em] text-clay\">Perfil del cliente</p>\n            <select id=\"profile-customer-select\" class=\"mt-5 w-full rounded-lg border-line bg-porcelain px-3 py-3 text-sm\"></select>\n            <div id=\"profile-card\" class=\"mt-6\"></div>\n          </aside>\n          <section class=\"lg:col-span-8\">\n            <div class=\"flex items-end justify-between gap-4\">\n              <div>\n                <h2 class=\"text-4xl font-extrabold tracking-tight\">Mis pedidos</h2>\n                <p class=\"mt-2 text-muted\">Cada cliente puede ver sus ordenes y el estado actual.</p>\n              </div>\n              <button class=\"nav-link rounded-lg border border-line bg-white px-4 py-3 text-sm font-bold\" data-page=\"tracking\">Rastrear</button>\n            </div>\n            <div id=\"customer-orders\" class=\"mt-7 space-y-4\"></div>\n          </section>\n        </div>\n      </div>\n    </section>\n\n    <section id=\"page-tracking\" class=\"page\">\n      <div class=\"mx-auto max-w-7xl px-5 py-12 md:px-8\">\n        <div class=\"flex flex-col justify-between gap-5 md:flex-row md:items-end\">\n          <div>\n            <p class=\"text-xs font-extrabold uppercase tracking-[0.2em] text-clay\">Estado del pedido</p>\n            <h2 class=\"mt-2 text-4xl font-extrabold tracking-tight\">Seguimiento</h2>\n          </div>\n          <select id=\"tracking-order-select\" class=\"rounded-lg border-line bg-white px-4 py-3 text-sm\"></select>\n        </div>\n        <div id=\"tracking-view\" class=\"mt-8\"></div>\n      </div>\n    </section>\n\n    <section id=\"page-admin\" class=\"page\">\n      <div class=\"mx-auto max-w-7xl px-5 py-12 md:px-8\">\n        <div class=\"flex flex-col justify-between gap-5 md:flex-row md:items-end\">\n          <div>\n            <p class=\"text-xs font-extrabold uppercase tracking-[0.2em] text-clay\">Panel administrativo</p>\n            <h2 class=\"mt-2 text-4xl font-extrabold tracking-tight\">Operaciones</h2>\n          </div>\n          <div class=\"rounded-lg border border-line bg-white px-4 py-3 text-sm text-muted\" id=\"sync-status\">Modo local listo para Supabase</div>\n        </div>\n        <div class=\"mt-8 grid grid-cols-1 gap-6 xl:grid-cols-12\">\n          <section class=\"rounded-xl bg-white p-5 shadow-sm xl:col-span-4\">\n            <h3 class=\"font-extrabold\">Productos</h3>\n            <form id=\"product-form\" class=\"mt-5 grid gap-3\">\n              <input type=\"hidden\" id=\"product-id\" />\n              <input id=\"product-name\" class=\"rounded-lg border-line\" placeholder=\"Nombre\" required />\n              <select id=\"product-category\" class=\"rounded-lg border-line\" required><option>Piel</option><option>Cabello</option><option>Kit</option></select>\n              <input id=\"product-price\" class=\"rounded-lg border-line\" type=\"number\" min=\"0\" step=\"0.01\" placeholder=\"Precio\" required />\n              <input id=\"product-stock\" class=\"rounded-lg border-line\" type=\"number\" min=\"0\" step=\"1\" placeholder=\"Inventario\" required />\n              <input id=\"product-image\" class=\"rounded-lg border-line\" placeholder=\"URL de imagen\" />\n              <textarea id=\"product-description\" class=\"rounded-lg border-line\" rows=\"3\" placeholder=\"Descripcion\"></textarea>\n              <button class=\"rounded-lg bg-sage px-5 py-3 font-bold text-white\">Guardar producto</button>\n              <button type=\"button\" id=\"product-reset\" class=\"rounded-lg border border-line px-5 py-3 font-bold\">Limpiar</button>\n            </form>\n            <div id=\"admin-products\" class=\"mt-5 max-h-[430px] space-y-3 overflow-auto pr-1 scroll-thin\"></div>\n          </section>\n\n          <section class=\"rounded-xl bg-white p-5 shadow-sm xl:col-span-4\">\n            <h3 class=\"font-extrabold\">Clientes</h3>\n            <form id=\"customer-form\" class=\"mt-5 grid gap-3\">\n              <input type=\"hidden\" id=\"customer-id\" />\n              <input id=\"customer-name\" class=\"rounded-lg border-line\" placeholder=\"Nombre completo\" required />\n              <input id=\"customer-email\" class=\"rounded-lg border-line\" type=\"email\" placeholder=\"Email\" required />\n              <input id=\"customer-phone\" class=\"rounded-lg border-line\" placeholder=\"Telefono\" />\n              <textarea id=\"customer-address\" class=\"rounded-lg border-line\" rows=\"3\" placeholder=\"Direccion de envio\"></textarea>\n              <button class=\"rounded-lg bg-sage px-5 py-3 font-bold text-white\">Guardar cliente</button>\n              <button type=\"button\" id=\"customer-reset\" class=\"rounded-lg border border-line px-5 py-3 font-bold\">Limpiar</button>\n            </form>\n            <div id=\"admin-customers\" class=\"mt-5 max-h-[430px] space-y-3 overflow-auto pr-1 scroll-thin\"></div>\n          </section>\n\n          <section class=\"rounded-xl bg-white p-5 shadow-sm xl:col-span-4\">\n            <h3 class=\"font-extrabold\">Pedidos y envios</h3>\n            <div id=\"admin-orders\" class=\"mt-5 max-h-[760px] space-y-4 overflow-auto pr-1 scroll-thin\"></div>\n          </section>\n        </div>\n      </div>\n    </section>\n  </main>\n\n  <div id=\"toast\" class=\"pointer-events-none fixed bottom-6 right-6 z-50 translate-y-3 rounded-lg bg-ink px-5 py-4 text-sm font-bold text-white opacity-0 shadow-2xl transition-all\"></div>\n\n  <script>\n    const STORAGE_KEY = \"catalina-commerce-v2\";\n    const orderStatuses = [\"Recibido\", \"Preparando\", \"Enviado\", \"En ruta\", \"Entregado\"];\n    const images = {\n      skin: \"https://images.unsplash.com/photo-1571781926291-c477ebfd024b?auto=format&fit=crop&w=900&q=80\",\n      hair: \"https://images.unsplash.com/photo-1522338242992-e1a54906a8da?auto=format&fit=crop&w=900&q=80\",\n      kit: \"https://images.unsplash.com/photo-1608248543803-ba4f8c70ae0b?auto=format&fit=crop&w=900&q=80\"\n    };\n    const seedState = {\n      products: [\n        { id: crypto.randomUUID(), name: \"Serum Barrera Ceramide 5%\", category: \"Piel\", price: 42, stock: 24, image: images.skin, description: \"Repara la barrera cutanea con ceramidas, niacinamida y pantenol.\" },\n        { id: crypto.randomUUID(), name: \"Limpieza Amino Gel\", category: \"Piel\", price: 26, stock: 38, image: \"https://images.unsplash.com/photo-1598440947619-2c35fc9aa908?auto=format&fit=crop&w=900&q=80\", description: \"Gel suave para limpieza diaria sin resecar.\" },\n        { id: crypto.randomUUID(), name: \"Aceite Capilar Biomimetic\", category: \"Cabello\", price: 36, stock: 18, image: images.hair, description: \"Tratamiento para brillo, puntas secas y control de frizz.\" },\n        { id: crypto.randomUUID(), name: \"Mascarilla Scalp Reset\", category: \"Cabello\", price: 31, stock: 21, image: \"https://images.unsplash.com/photo-1596755094514-f87e34085b2c?auto=format&fit=crop&w=900&q=80\", description: \"Mascarilla de cuero cabelludo con arcillas suaves y prebioticos.\" },\n        { id: crypto.randomUUID(), name: \"Kit Rutina Glow\", category: \"Kit\", price: 89, stock: 12, image: images.kit, description: \"Rutina completa con limpieza, serum y crema hidratante.\" }\n      ],\n      customers: [\n        { id: crypto.randomUUID(), name: \"Camila Torres\", email: \"camila@example.com\", phone: \"+1 305 555 0144\", address: \"1200 Brickell Ave, Miami, FL\" },\n        { id: crypto.randomUUID(), name: \"Lucia Herrera\", email: \"lucia@example.com\", phone: \"+1 786 555 0182\", address: \"88 Miracle Mile, Coral Gables, FL\" }\n      ],\n      orders: []\n    };\n    seedState.orders = [\n      makeOrder(seedState.customers[0].id, [seedState.products[0], seedState.products[2]], \"En ruta\"),\n      makeOrder(seedState.customers[1].id, [seedState.products[4]], \"Preparando\")\n    ];\n\n    let state = loadState();\n    let cart = [];\n    let supabaseClient = null;\n\n    function makeOrder(customerId, products, status = \"Recibido\") {\n      const createdAt = new Date(Date.now() - Math.floor(Math.random() * 5) * 86400000).toISOString();\n      return {\n        id: \"CAT-\" + Math.floor(100000 + Math.random() * 899999),\n        customerId,\n        status,\n        trackingCode: \"CL\" + Math.floor(10000000 + Math.random() * 89999999),\n        carrier: \"Catalina Express\",\n        createdAt,\n        eta: new Date(Date.now() + 4 * 86400000).toISOString().slice(0, 10),\n        items: products.map(product => ({ productId: product.id, name: product.name, price: product.price, qty: 1, image: product.image })),\n        history: buildHistory(status, createdAt)\n      };\n    }\n\n    function buildHistory(status, createdAt) {\n      const index = orderStatuses.indexOf(status);\n      return orderStatuses.slice(0, Math.max(index + 1, 1)).map((name, i) => ({\n        status: name,\n        note: statusNote(name),\n        at: new Date(new Date(createdAt).getTime() + i * 7200000).toISOString()\n      }));\n    }\n\n    function statusNote(status) {\n      return {\n        Recibido: \"Pedido recibido y pago validado.\",\n        Preparando: \"Productos separados y control de calidad iniciado.\",\n        Enviado: \"Paquete entregado al transportista.\",\n        \"En ruta\": \"Pedido en camino al destino.\",\n        Entregado: \"Entrega completada.\"\n      }[status] || \"Actualizacion registrada.\";\n    }\n\n    function loadState() {\n      const saved = localStorage.getItem(STORAGE_KEY);\n      if (!saved) return seedState;\n      try { return JSON.parse(saved); } catch { return seedState; }\n    }\n\n    function persist() {\n      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));\n      renderAll();\n    }\n\n    function money(value) {\n      return new Intl.NumberFormat(\"es-US\", { style: \"currency\", currency: \"USD\" }).format(value);\n    }\n\n    function showPage(id) {\n      document.querySelectorAll(\".page\").forEach(page => page.classList.remove(\"active\"));\n      const target = document.getElementById(\"page-\" + id);\n      if (target) target.classList.add(\"active\");\n      window.scrollTo({ top: 0, behavior: \"smooth\" });\n    }\n\n    function showToast(message) {\n      const toast = document.getElementById(\"toast\");\n      toast.textContent = message;\n      toast.classList.remove(\"opacity-0\", \"translate-y-3\");\n      setTimeout(() => toast.classList.add(\"opacity-0\", \"translate-y-3\"), 2100);\n    }\n\n    function productCard(product) {\n      return `<article class=\"overflow-hidden rounded-xl bg-white shadow-sm\">\n        <img class=\"h-64 w-full object-cover\" src=\"${product.image || images.skin}\" alt=\"${product.name}\">\n        <div class=\"p-5\">\n          <div class=\"flex items-start justify-between gap-4\">\n            <div><p class=\"text-xs font-bold uppercase tracking-widest text-clay\">${product.category}</p><h3 class=\"mt-1 text-xl font-extrabold\">${product.name}</h3></div>\n            <strong>${money(product.price)}</strong>\n          </div>\n          <p class=\"mt-3 min-h-[48px] text-sm leading-6 text-muted\">${product.description || \"\"}</p>\n          <div class=\"mt-5 flex items-center justify-between\">\n            <span class=\"text-xs font-bold uppercase tracking-widest ${product.stock > 0 ? \"text-sage\" : \"text-clay\"}\">${product.stock} disponibles</span>\n            <button class=\"add-to-cart rounded-lg bg-ink px-4 py-3 text-sm font-bold text-white hover:bg-sage\" data-id=\"${product.id}\" ${product.stock <= 0 ? \"disabled\" : \"\"}>Agregar</button>\n          </div>\n        </div>\n      </article>`;\n    }\n\n    function renderCatalog() {\n      const term = document.getElementById(\"catalog-search\").value.toLowerCase();\n      const category = document.getElementById(\"catalog-filter\").value;\n      const products = state.products.filter(product => {\n        const matchesTerm = [product.name, product.description, product.category].join(\" \").toLowerCase().includes(term);\n        const matchesCategory = category === \"all\" || product.category === category;\n        return matchesTerm && matchesCategory;\n      });\n      document.getElementById(\"product-grid\").innerHTML = products.map(productCard).join(\"\") || emptyBlock(\"No hay productos con ese filtro.\");\n    }\n\n    function addToCart(productId) {\n      const product = state.products.find(item => item.id === productId);\n      if (!product || product.stock <= 0) return;\n      const existing = cart.find(item => item.productId === productId);\n      if (existing) existing.qty += 1;\n      else cart.push({ productId, name: product.name, price: product.price, qty: 1, image: product.image });\n      renderCart();\n      showToast(\"Producto agregado\");\n    }\n\n    function changeCartQty(productId, delta) {\n      const item = cart.find(line => line.productId === productId);\n      if (!item) return;\n      item.qty += delta;\n      if (item.qty <= 0) cart = cart.filter(line => line.productId !== productId);\n      renderCart();\n    }\n\n    function renderCart() {\n      const items = document.getElementById(\"cart-items\");\n      const empty = document.getElementById(\"cart-empty\");\n      const count = cart.reduce((sum, item) => sum + item.qty, 0);\n      const subtotal = cart.reduce((sum, item) => sum + item.price * item.qty, 0);\n      const shipping = subtotal > 0 ? 6.95 : 0;\n      document.getElementById(\"cart-pill\").textContent = count;\n      document.getElementById(\"summary-subtotal\").textContent = money(subtotal);\n      document.getElementById(\"summary-shipping\").textContent = money(shipping);\n      document.getElementById(\"summary-total\").textContent = money(subtotal + shipping);\n      empty.classList.toggle(\"hidden\", cart.length > 0);\n      items.innerHTML = cart.map(item => `<div class=\"flex gap-4 rounded-xl bg-white p-4 shadow-sm\">\n        <img class=\"h-28 w-24 rounded-lg object-cover\" src=\"${item.image}\" alt=\"${item.name}\">\n        <div class=\"flex flex-1 flex-col justify-between\">\n          <div class=\"flex justify-between gap-4\"><h3 class=\"font-extrabold\">${item.name}</h3><strong>${money(item.price * item.qty)}</strong></div>\n          <div class=\"flex items-center justify-between\">\n            <div class=\"flex items-center rounded-lg bg-mist\">\n              <button class=\"cart-qty px-3 py-2\" data-id=\"${item.productId}\" data-delta=\"-1\"><span class=\"material-symbols-outlined text-base\">remove</span></button>\n              <span class=\"px-2 text-sm font-bold\">${item.qty}</span>\n              <button class=\"cart-qty px-3 py-2\" data-id=\"${item.productId}\" data-delta=\"1\"><span class=\"material-symbols-outlined text-base\">add</span></button>\n            </div>\n            <button class=\"cart-remove text-sm font-bold text-clay\" data-id=\"${item.productId}\">Quitar</button>\n          </div>\n        </div>\n      </div>`).join(\"\");\n    }\n\n    function renderSelectors() {\n      const customerOptions = state.customers.map(customer => `<option value=\"${customer.id}\">${customer.name}</option>`).join(\"\");\n      [\"checkout-customer\", \"profile-customer-select\"].forEach(id => document.getElementById(id).innerHTML = customerOptions);\n      document.getElementById(\"tracking-order-select\").innerHTML = state.orders.map(order => `<option value=\"${order.id}\">${order.id} - ${customerName(order.customerId)}</option>`).join(\"\");\n    }\n\n    function renderProfile() {\n      const customerId = document.getElementById(\"profile-customer-select\").value || state.customers[0]?.id;\n      const customer = state.customers.find(item => item.id === customerId);\n      if (!customer) return;\n      document.getElementById(\"profile-card\").innerHTML = `<div class=\"rounded-lg bg-porcelain p-5\">\n        <h3 class=\"text-2xl font-extrabold\">${customer.name}</h3>\n        <p class=\"mt-2 text-sm text-muted\">${customer.email}</p>\n        <p class=\"mt-1 text-sm text-muted\">${customer.phone || \"\"}</p>\n        <p class=\"mt-5 text-sm leading-6\">${customer.address || \"Sin direccion guardada\"}</p>\n      </div>`;\n      const orders = state.orders.filter(order => order.customerId === customerId);\n      document.getElementById(\"customer-orders\").innerHTML = orders.map(orderSummary).join(\"\") || emptyBlock(\"Este cliente aun no tiene pedidos.\");\n    }\n\n    function orderSummary(order) {\n      return `<article class=\"rounded-xl bg-white p-5 shadow-sm\">\n        <div class=\"flex flex-col justify-between gap-4 md:flex-row md:items-center\">\n          <div><p class=\"text-xs font-bold uppercase tracking-widest text-muted\">${new Date(order.createdAt).toLocaleDateString()}</p><h3 class=\"mt-1 text-xl font-extrabold\">${order.id}</h3><p class=\"text-sm text-muted\">${order.items.length} producto(s) - ${money(orderTotal(order))}</p></div>\n          <div class=\"flex items-center gap-3\"><span class=\"rounded-full bg-mist px-3 py-1 text-xs font-extrabold uppercase tracking-widest text-sage\">${order.status}</span><button class=\"track-order rounded-lg border border-line px-4 py-3 text-sm font-bold\" data-id=\"${order.id}\">Ver estado</button></div>\n        </div>\n      </article>`;\n    }\n\n    function renderTracking() {\n      const orderId = document.getElementById(\"tracking-order-select\").value || state.orders[0]?.id;\n      const order = state.orders.find(item => item.id === orderId);\n      const target = document.getElementById(\"tracking-view\");\n      if (!order) { target.innerHTML = emptyBlock(\"No hay pedidos para rastrear.\"); return; }\n      const progress = Math.max(orderStatuses.indexOf(order.status), 0);\n      target.innerHTML = `<div class=\"grid grid-cols-1 gap-6 lg:grid-cols-12\">\n        <section class=\"rounded-xl bg-white p-6 shadow-sm lg:col-span-8\">\n          <div class=\"flex flex-col justify-between gap-4 md:flex-row md:items-start\">\n            <div><p class=\"text-xs font-bold uppercase tracking-widest text-muted\">Pedido ${order.id}</p><h3 class=\"mt-1 text-3xl font-extrabold\">${order.status}</h3><p class=\"mt-2 text-muted\">Entrega estimada: ${order.eta}</p></div>\n            <div class=\"rounded-lg bg-mist px-4 py-3 text-sm font-bold\">Tracking ${order.trackingCode}</div>\n          </div>\n          <div class=\"mt-10 grid grid-cols-5 gap-2\">\n            ${orderStatuses.map((status, i) => `<div class=\"text-center\">\n              <div class=\"mx-auto flex h-11 w-11 items-center justify-center rounded-full ${i <= progress ? \"bg-sage text-white\" : \"bg-mist text-muted\"}\"><span class=\"material-symbols-outlined text-lg\">${i <= progress ? \"check\" : \"radio_button_unchecked\"}</span></div>\n              <p class=\"mt-3 text-[10px] font-extrabold uppercase tracking-widest ${i === progress ? \"text-sage\" : \"text-muted\"}\">${status}</p>\n            </div>`).join(\"\")}\n          </div>\n          <div class=\"mt-10 space-y-5\">${order.history.slice().reverse().map(event => `<div class=\"border-l-2 border-sage pl-5\"><p class=\"font-extrabold\">${event.status}</p><p class=\"text-sm text-muted\">${event.note}</p><p class=\"mt-1 text-xs font-bold uppercase tracking-widest text-muted\">${new Date(event.at).toLocaleString()}</p></div>`).join(\"\")}</div>\n        </section>\n        <aside class=\"rounded-xl bg-white p-6 shadow-sm lg:col-span-4\">\n          <h3 class=\"font-extrabold\">Resumen</h3>\n          <p class=\"mt-2 text-sm text-muted\">${customerName(order.customerId)}</p>\n          <div class=\"mt-6 space-y-4\">${order.items.map(item => `<div class=\"flex gap-3\"><img class=\"h-16 w-14 rounded object-cover\" src=\"${item.image}\" alt=\"${item.name}\"><div class=\"flex-1\"><p class=\"text-sm font-bold\">${item.name}</p><p class=\"text-xs text-muted\">Qty ${item.qty} - ${money(item.price)}</p></div></div>`).join(\"\")}</div>\n          <div class=\"mt-6 border-t border-line pt-5\"><div class=\"flex justify-between font-extrabold\"><span>Total</span><span>${money(orderTotal(order))}</span></div></div>\n        </aside>\n      </div>`;\n    }\n\n    function renderAdmin() {\n      document.getElementById(\"admin-products\").innerHTML = state.products.map(product => `<div class=\"rounded-lg border border-line p-3\">\n        <div class=\"flex justify-between gap-3\"><div><p class=\"font-bold\">${product.name}</p><p class=\"text-xs text-muted\">${product.category} - ${money(product.price)} - Stock ${product.stock}</p></div><button class=\"edit-product text-sm font-bold text-sage\" data-id=\"${product.id}\">Editar</button></div>\n      </div>`).join(\"\");\n      document.getElementById(\"admin-customers\").innerHTML = state.customers.map(customer => `<div class=\"rounded-lg border border-line p-3\">\n        <div class=\"flex justify-between gap-3\"><div><p class=\"font-bold\">${customer.name}</p><p class=\"text-xs text-muted\">${customer.email}</p></div><button class=\"edit-customer text-sm font-bold text-sage\" data-id=\"${customer.id}\">Editar</button></div>\n      </div>`).join(\"\");\n      document.getElementById(\"admin-orders\").innerHTML = state.orders.map(order => `<div class=\"rounded-lg border border-line p-4\">\n        <div class=\"flex items-start justify-between gap-4\"><div><p class=\"font-extrabold\">${order.id}</p><p class=\"text-sm text-muted\">${customerName(order.customerId)} - ${money(orderTotal(order))}</p></div><span class=\"rounded-full bg-mist px-3 py-1 text-[10px] font-extrabold uppercase tracking-widest\">${order.status}</span></div>\n        <label class=\"mt-4 block text-xs font-bold uppercase tracking-widest text-muted\">Estado</label>\n        <select class=\"order-status mt-2 w-full rounded-lg border-line bg-porcelain text-sm\" data-id=\"${order.id}\">${orderStatuses.map(status => `<option ${status === order.status ? \"selected\" : \"\"}>${status}</option>`).join(\"\")}</select>\n        <label class=\"mt-3 block text-xs font-bold uppercase tracking-widest text-muted\">Transportista</label>\n        <input class=\"order-carrier mt-2 w-full rounded-lg border-line text-sm\" data-id=\"${order.id}\" value=\"${order.carrier}\">\n      </div>`).join(\"\");\n    }\n\n    function renderMetrics() {\n      document.getElementById(\"metric-orders\").textContent = state.orders.length;\n      document.getElementById(\"metric-customers\").textContent = state.customers.length;\n      document.getElementById(\"metric-revenue\").textContent = money(state.orders.reduce((sum, order) => sum + orderTotal(order), 0));\n    }\n\n    function renderAll() {\n      renderMetrics();\n      renderCatalog();\n      renderSelectors();\n      renderCart();\n      renderProfile();\n      renderTracking();\n      renderAdmin();\n    }\n\n    function orderTotal(order) {\n      return order.items.reduce((sum, item) => sum + item.price * item.qty, 0);\n    }\n\n    function customerName(id) {\n      return state.customers.find(customer => customer.id === id)?.name || \"Cliente eliminado\";\n    }\n\n    function emptyBlock(message) {\n      return `<div class=\"rounded-xl border border-dashed border-line bg-white p-8 text-center text-muted\">${message}</div>`;\n    }\n\n    function createOrderFromCart() {\n      if (!cart.length) return showToast(\"Agrega productos primero\");\n      const customerId = document.getElementById(\"checkout-customer\").value;\n      const products = cart.map(item => state.products.find(product => product.id === item.productId)).filter(Boolean);\n      const order = makeOrder(customerId, products);\n      order.items = cart.map(item => ({ ...item }));\n      state.orders.unshift(order);\n      cart.forEach(item => {\n        const product = state.products.find(product => product.id === item.productId);\n        if (product) product.stock = Math.max(0, product.stock - item.qty);\n      });\n      cart = [];\n      persist();\n      document.getElementById(\"tracking-order-select\").value = order.id;\n      showPage(\"tracking\");\n      showToast(\"Pedido creado\");\n    }\n\n    function saveProduct(event) {\n      event.preventDefault();\n      const id = document.getElementById(\"product-id\").value || crypto.randomUUID();\n      const product = {\n        id,\n        name: document.getElementById(\"product-name\").value.trim(),\n        category: document.getElementById(\"product-category\").value,\n        price: Number(document.getElementById(\"product-price\").value),\n        stock: Number(document.getElementById(\"product-stock\").value),\n        image: document.getElementById(\"product-image\").value.trim() || images.skin,\n        description: document.getElementById(\"product-description\").value.trim()\n      };\n      const index = state.products.findIndex(item => item.id === id);\n      if (index >= 0) state.products[index] = product;\n      else state.products.unshift(product);\n      event.target.reset();\n      document.getElementById(\"product-id\").value = \"\";\n      persist();\n      showToast(\"Producto guardado\");\n    }\n\n    function saveCustomer(event) {\n      event.preventDefault();\n      const id = document.getElementById(\"customer-id\").value || crypto.randomUUID();\n      const customer = {\n        id,\n        name: document.getElementById(\"customer-name\").value.trim(),\n        email: document.getElementById(\"customer-email\").value.trim(),\n        phone: document.getElementById(\"customer-phone\").value.trim(),\n        address: document.getElementById(\"customer-address\").value.trim()\n      };\n      const index = state.customers.findIndex(item => item.id === id);\n      if (index >= 0) state.customers[index] = customer;\n      else state.customers.unshift(customer);\n      event.target.reset();\n      document.getElementById(\"customer-id\").value = \"\";\n      persist();\n      showToast(\"Cliente guardado\");\n    }\n\n    function fillProduct(id) {\n      const product = state.products.find(item => item.id === id);\n      if (!product) return;\n      document.getElementById(\"product-id\").value = product.id;\n      document.getElementById(\"product-name\").value = product.name;\n      document.getElementById(\"product-category\").value = product.category;\n      document.getElementById(\"product-price\").value = product.price;\n      document.getElementById(\"product-stock\").value = product.stock;\n      document.getElementById(\"product-image\").value = product.image;\n      document.getElementById(\"product-description\").value = product.description;\n    }\n\n    function fillCustomer(id) {\n      const customer = state.customers.find(item => item.id === id);\n      if (!customer) return;\n      document.getElementById(\"customer-id\").value = customer.id;\n      document.getElementById(\"customer-name\").value = customer.name;\n      document.getElementById(\"customer-email\").value = customer.email;\n      document.getElementById(\"customer-phone\").value = customer.phone;\n      document.getElementById(\"customer-address\").value = customer.address;\n    }\n\n    function updateOrder(id, key, value) {\n      const order = state.orders.find(item => item.id === id);\n      if (!order) return;\n      order[key] = value;\n      if (key === \"status\") order.history = buildHistory(value, order.createdAt);\n      persist();\n      showToast(\"Pedido actualizado\");\n    }\n\n    function initSupabase() {\n      const url = window.CATALINA_SUPABASE_URL || \"\";\n      const key = window.CATALINA_SUPABASE_PUBLISHABLE_KEY || \"\";\n      if (url && key && window.supabase) {\n        supabaseClient = window.supabase.createClient(url, key);\n        document.getElementById(\"sync-status\").textContent = \"Supabase configurado\";\n      }\n    }\n\n    document.addEventListener(\"click\", event => {\n      const link = event.target.closest(\".nav-link\");\n      if (link?.dataset.page) showPage(link.dataset.page);\n      const add = event.target.closest(\".add-to-cart\");\n      if (add?.dataset.id) addToCart(add.dataset.id);\n      const qty = event.target.closest(\".cart-qty\");\n      if (qty) changeCartQty(qty.dataset.id, Number(qty.dataset.delta));\n      const remove = event.target.closest(\".cart-remove\");\n      if (remove) { cart = cart.filter(item => item.productId !== remove.dataset.id); renderCart(); }\n      const track = event.target.closest(\".track-order\");\n      if (track) { document.getElementById(\"tracking-order-select\").value = track.dataset.id; showPage(\"tracking\"); renderTracking(); }\n      const editProduct = event.target.closest(\".edit-product\");\n      if (editProduct) fillProduct(editProduct.dataset.id);\n      const editCustomer = event.target.closest(\".edit-customer\");\n      if (editCustomer) fillCustomer(editCustomer.dataset.id);\n    });\n\n    document.addEventListener(\"change\", event => {\n      if (event.target.id === \"profile-customer-select\") renderProfile();\n      if (event.target.id === \"tracking-order-select\") renderTracking();\n      if (event.target.classList.contains(\"order-status\")) updateOrder(event.target.dataset.id, \"status\", event.target.value);\n      if (event.target.classList.contains(\"order-carrier\")) updateOrder(event.target.dataset.id, \"carrier\", event.target.value);\n    });\n    document.getElementById(\"catalog-search\").addEventListener(\"input\", renderCatalog);\n    document.getElementById(\"catalog-filter\").addEventListener(\"change\", renderCatalog);\n    document.getElementById(\"checkout-btn\").addEventListener(\"click\", createOrderFromCart);\n    document.getElementById(\"product-form\").addEventListener(\"submit\", saveProduct);\n    document.getElementById(\"customer-form\").addEventListener(\"submit\", saveCustomer);\n    document.getElementById(\"product-reset\").addEventListener(\"click\", () => { document.getElementById(\"product-form\").reset(); document.getElementById(\"product-id\").value = \"\"; });\n    document.getElementById(\"customer-reset\").addEventListener(\"click\", () => { document.getElementById(\"customer-form\").reset(); document.getElementById(\"customer-id\").value = \"\"; });\n\n    initSupabase();\n    renderAll();\n  </script>\n</body>\n</html>\n";
const schema = "-- Catalina Cosmetic ecommerce schema for Supabase.\n-- Run this in the Supabase SQL editor after enabling Auth.\n\ncreate extension if not exists pgcrypto;\n\ncreate table if not exists public.products (\n  id uuid primary key default gen_random_uuid(),\n  name text not null,\n  category text not null check (category in ('Piel', 'Cabello', 'Kit')),\n  description text,\n  price numeric(10,2) not null check (price >= 0),\n  stock integer not null default 0 check (stock >= 0),\n  image_url text,\n  is_active boolean not null default true,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n);\n\ncreate table if not exists public.customer_profiles (\n  id uuid primary key references auth.users(id) on delete cascade,\n  full_name text not null,\n  email text not null,\n  phone text,\n  shipping_address text,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n);\n\ncreate table if not exists public.orders (\n  id uuid primary key default gen_random_uuid(),\n  order_number text not null unique,\n  customer_id uuid not null references public.customer_profiles(id) on delete restrict,\n  status text not null default 'Recibido' check (status in ('Recibido', 'Preparando', 'Enviado', 'En ruta', 'Entregado', 'Cancelado')),\n  carrier text,\n  tracking_code text,\n  subtotal numeric(10,2) not null default 0 check (subtotal >= 0),\n  shipping_amount numeric(10,2) not null default 0 check (shipping_amount >= 0),\n  total numeric(10,2) generated always as (subtotal + shipping_amount) stored,\n  estimated_delivery date,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n);\n\ncreate table if not exists public.order_items (\n  id uuid primary key default gen_random_uuid(),\n  order_id uuid not null references public.orders(id) on delete cascade,\n  product_id uuid references public.products(id) on delete set null,\n  product_name text not null,\n  unit_price numeric(10,2) not null check (unit_price >= 0),\n  quantity integer not null check (quantity > 0),\n  created_at timestamptz not null default now()\n);\n\ncreate table if not exists public.shipment_events (\n  id uuid primary key default gen_random_uuid(),\n  order_id uuid not null references public.orders(id) on delete cascade,\n  status text not null check (status in ('Recibido', 'Preparando', 'Enviado', 'En ruta', 'Entregado', 'Cancelado')),\n  note text,\n  event_at timestamptz not null default now(),\n  created_at timestamptz not null default now()\n);\n\ncreate index if not exists idx_products_active_category on public.products (is_active, category);\ncreate index if not exists idx_orders_customer_created on public.orders (customer_id, created_at desc);\ncreate index if not exists idx_order_items_order on public.order_items (order_id);\ncreate index if not exists idx_shipment_events_order_event on public.shipment_events (order_id, event_at desc);\n\nalter table public.products enable row level security;\nalter table public.customer_profiles enable row level security;\nalter table public.orders enable row level security;\nalter table public.order_items enable row level security;\nalter table public.shipment_events enable row level security;\n\ncreate or replace function public.is_admin()\nreturns boolean\nlanguage sql\nstable\nas $$\n  select coalesce((auth.jwt() -> 'app_metadata' ->> 'role') = 'admin', false);\n$$;\n\ndrop policy if exists \"Anyone can read active products\" on public.products;\ncreate policy \"Anyone can read active products\"\non public.products for select\nto anon, authenticated\nusing (is_active = true);\n\ndrop policy if exists \"Admins manage products\" on public.products;\ncreate policy \"Admins manage products\"\non public.products for all\nto authenticated\nusing (public.is_admin())\nwith check (public.is_admin());\n\ndrop policy if exists \"Customers read own profile\" on public.customer_profiles;\ncreate policy \"Customers read own profile\"\non public.customer_profiles for select\nto authenticated\nusing ((select auth.uid()) = id or public.is_admin());\n\ndrop policy if exists \"Customers update own profile\" on public.customer_profiles;\ncreate policy \"Customers update own profile\"\non public.customer_profiles for update\nto authenticated\nusing ((select auth.uid()) = id or public.is_admin())\nwith check ((select auth.uid()) = id or public.is_admin());\n\ndrop policy if exists \"Customers create own profile\" on public.customer_profiles;\ncreate policy \"Customers create own profile\"\non public.customer_profiles for insert\nto authenticated\nwith check ((select auth.uid()) = id or public.is_admin());\n\ndrop policy if exists \"Customers read own orders\" on public.orders;\ncreate policy \"Customers read own orders\"\non public.orders for select\nto authenticated\nusing (customer_id = (select auth.uid()) or public.is_admin());\n\ndrop policy if exists \"Admins manage orders\" on public.orders;\ncreate policy \"Admins manage orders\"\non public.orders for all\nto authenticated\nusing (public.is_admin())\nwith check (public.is_admin());\n\ndrop policy if exists \"Customers read own order items\" on public.order_items;\ncreate policy \"Customers read own order items\"\non public.order_items for select\nto authenticated\nusing (\n  exists (\n    select 1\n    from public.orders\n    where orders.id = order_items.order_id\n      and (orders.customer_id = (select auth.uid()) or public.is_admin())\n  )\n);\n\ndrop policy if exists \"Admins manage order items\" on public.order_items;\ncreate policy \"Admins manage order items\"\non public.order_items for all\nto authenticated\nusing (public.is_admin())\nwith check (public.is_admin());\n\ndrop policy if exists \"Customers read own shipment events\" on public.shipment_events;\ncreate policy \"Customers read own shipment events\"\non public.shipment_events for select\nto authenticated\nusing (\n  exists (\n    select 1\n    from public.orders\n    where orders.id = shipment_events.order_id\n      and (orders.customer_id = (select auth.uid()) or public.is_admin())\n  )\n);\n\ndrop policy if exists \"Admins manage shipment events\" on public.shipment_events;\ncreate policy \"Admins manage shipment events\"\non public.shipment_events for all\nto authenticated\nusing (public.is_admin())\nwith check (public.is_admin());\n";

export default {
  async fetch(request) {
    const url = new URL(request.url);

    if (url.pathname === "/supabase-schema.sql") {
      return new Response(schema, {
        headers: {
          "content-type": "text/plain; charset=utf-8",
          "cache-control": "public, max-age=300"
        }
      });
    }

    return new Response(html, {
      headers: {
        "content-type": "text/html; charset=utf-8",
        "cache-control": "public, max-age=300"
      }
    });
  }
};
